import r from"os";import t from"path";import n from"fs";function o(n){var o=process.env[n]||t.join.apply(t,[r.homedir()].concat({XDG_CONFIG_HOME:[".config"],XDG_DATA_HOME:[".local","share"],XDG_STATE_HOME:[".local","state"]}[n]));return t.join(o,"zen")}export function config(){return o("XDG_CONFIG_HOME")}export function data(){return o("XDG_DATA_HOME")}export function state(){return o("XDG_STATE_HOME")}export function ensure(r){try{n.existsSync(r)||n.mkdirSync(r,{recursive:!0})}catch(r){}return r}